entrypoint:
const { event, data } = context;
if (event !== 'ticket.created' && event !== 'ticket.updated') return;
const cfg = cliaas.config;
const mappings = cfg.mappings || [];
for (const m of mappings) {
  const val = data[m.source] || data.fields?.[m.source];
  if (val) cliaas.log.info(`Syncing ${m.source} -> ${m.target}: ${val}`);
}
